CREATE TABLE IF NOT EXISTS kiosk_accessibility_settings (id BIGSERIAL PRIMARY KEY, tenant_id BIGINT NOT NULL, high_contrast BOOLEAN NOT NULL DEFAULT FALSE, large_font BOOLEAN NOT NULL DEFAULT FALSE, simplified_navigation BOOLEAN NOT NULL DEFAULT FALSE, senior_mode BOOLEAN NOT NULL DEFAULT FALSE, updated_at TIMESTAMP NOT NULL DEFAULT NOW());
CREATE TABLE IF NOT EXISTS kiosk_voice_sessions (id BIGSERIAL PRIMARY KEY, tenant_id BIGINT NOT NULL, language_code VARCHAR(10) NOT NULL DEFAULT 'pt-BR', status VARCHAR(20) NOT NULL DEFAULT 'ACTIVE');
CREATE TABLE IF NOT EXISTS kiosk_guided_flows (id BIGSERIAL PRIMARY KEY, tenant_id BIGINT NOT NULL, flow_name VARCHAR(120) NOT NULL, is_active BOOLEAN NOT NULL DEFAULT TRUE, steps_json JSONB NOT NULL);
CREATE TABLE IF NOT EXISTS kiosk_language_settings (id BIGSERIAL PRIMARY KEY, tenant_id BIGINT NOT NULL, language_code VARCHAR(10) NOT NULL, is_default BOOLEAN NOT NULL DEFAULT FALSE);
